import{_ as t,o as a,c as i,ae as r}from"./chunks/framework.Czhw_PXq.js";const u=JSON.parse('{"title":"Repo Health Check — Governance Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"governance/repo-health-check.md","filePath":"governance/repo-health-check.md"}'),o={name:"governance/repo-health-check.md"};function s(n,e,d,l,h,c){return a(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="repo-health-check-—-governance-documentation" tabindex="-1">Repo Health Check — Governance Documentation <a class="header-anchor" href="#repo-health-check-—-governance-documentation" aria-label="Permalink to &quot;Repo Health Check — Governance Documentation&quot;">​</a></h1><p><strong>Issue:</strong> <a href="https://github.com/OpenSIN-AI/OpenSIN-documentation/issues/98" target="_blank" rel="noreferrer">#98</a><strong>Status:</strong> Active <strong>Owner:</strong> SIN-Zeus (control-plane)</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <strong>Repo Health Check</strong> is a GitHub Action that automatically scans repositories in the OpenSIN-AI organization for compliance with project standards. It ensures every repo meets the minimum requirements for documentation, security, and A2A agent discoverability.</p><hr><h2 id="what-it-checks" tabindex="-1">What It Checks <a class="header-anchor" href="#what-it-checks" aria-label="Permalink to &quot;What It Checks&quot;">​</a></h2><h3 id="all-repositories" tabindex="-1">All Repositories <a class="header-anchor" href="#all-repositories" aria-label="Permalink to &quot;All Repositories&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Check</th><th>Description</th><th>Severity</th></tr></thead><tbody><tr><td><code>README.md</code></td><td>Project documentation exists</td><td>High</td></tr><tr><td><code>LICENSE</code></td><td>Open source license file</td><td>Medium</td></tr><tr><td><code>.gitignore</code></td><td>Git ignore configuration</td><td>Low</td></tr><tr><td>Secret Detection</td><td>Scans for hardcoded API keys, passwords, tokens</td><td>Critical</td></tr><tr><td>GitHub Topics</td><td>Repository has at least 1 topic</td><td>Medium</td></tr></tbody></table><h3 id="a2a-agent-repositories" tabindex="-1">A2A Agent Repositories <a class="header-anchor" href="#a2a-agent-repositories" aria-label="Permalink to &quot;A2A Agent Repositories&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Check</th><th>Description</th><th>Severity</th></tr></thead><tbody><tr><td><code>AGENTS.md</code></td><td>Agent operating manual</td><td>Critical</td></tr><tr><td><code>agent.json</code></td><td>A2A agent card metadata</td><td>High</td></tr><tr><td>Topic <code>opnsin-agent</code></td><td>Discoverability tag</td><td>Medium</td></tr></tbody></table><h3 id="mcp-server-repositories" tabindex="-1">MCP Server Repositories <a class="header-anchor" href="#mcp-server-repositories" aria-label="Permalink to &quot;MCP Server Repositories&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Check</th><th>Description</th><th>Severity</th></tr></thead><tbody><tr><td><code>README.md</code></td><td>Server documentation</td><td>Critical</td></tr><tr><td><code>AGENTS.md</code></td><td>Agent operating manual</td><td>Critical</td></tr><tr><td><code>mcp-config.json</code></td><td>MCP server configuration</td><td>High</td></tr><tr><td>Topic <code>opnsin-mcp</code></td><td>Discoverability tag</td><td>Medium</td></tr></tbody></table><hr><h2 id="triggers" tabindex="-1">Triggers <a class="header-anchor" href="#triggers" aria-label="Permalink to &quot;Triggers&quot;">​</a></h2><h3 id="automatic" tabindex="-1">Automatic <a class="header-anchor" href="#automatic" aria-label="Permalink to &quot;Automatic&quot;">​</a></h3><ul><li><strong>On Push to <code>main</code>:</strong> Scans the current repository</li><li><strong>On Pull Request to <code>main</code>:</strong> Scans the current repository</li></ul><h3 id="manual" tabindex="-1">Manual <a class="header-anchor" href="#manual" aria-label="Permalink to &quot;Manual&quot;">​</a></h3><ul><li><strong>Workflow Dispatch:</strong> Can scan all repositories in the organization</li></ul><hr><h2 id="how-to-run" tabindex="-1">How to Run <a class="header-anchor" href="#how-to-run" aria-label="Permalink to &quot;How to Run&quot;">​</a></h2><h3 id="automatic-no-action-required" tabindex="-1">Automatic (No Action Required) <a class="header-anchor" href="#automatic-no-action-required" aria-label="Permalink to &quot;Automatic (No Action Required)&quot;">​</a></h3><p>The workflow runs automatically on every push and pull request to <code>main</code>. Results appear in:</p><ul><li><strong>PR:</strong> Check runs tab</li><li><strong>Push:</strong> Actions tab → &quot;Repo Health Check&quot;</li></ul><h3 id="manual-organization-wide-scan" tabindex="-1">Manual Organization-Wide Scan <a class="header-anchor" href="#manual-organization-wide-scan" aria-label="Permalink to &quot;Manual Organization-Wide Scan&quot;">​</a></h3><ol><li>Go to <strong>Actions</strong> tab</li><li>Select <strong>Repo Health Check</strong></li><li>Click <strong>Run workflow</strong></li><li>Check <strong>&quot;Scan all repos in OpenSIN-AI org&quot;</strong></li><li>Click <strong>Run workflow</strong></li></ol><h3 id="via-github-cli" tabindex="-1">Via GitHub CLI <a class="header-anchor" href="#via-github-cli" aria-label="Permalink to &quot;Via GitHub CLI&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Trigger workflow dispatch</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> workflow</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> repo-health-check.yml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --ref</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scan_all_repos=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> org=OpenSIN-AI</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Check results</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> view</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --log</span></span></code></pre></div><hr><h2 id="interpreting-results" tabindex="-1">Interpreting Results <a class="header-anchor" href="#interpreting-results" aria-label="Permalink to &quot;Interpreting Results&quot;">​</a></h2><h3 id="github-step-summary" tabindex="-1">GitHub Step Summary <a class="header-anchor" href="#github-step-summary" aria-label="Permalink to &quot;GitHub Step Summary&quot;">​</a></h3><p>Results are written to <code>$GITHUB_STEP_SUMMARY</code> and displayed in:</p><ul><li>PR comment (for pull_request trigger)</li><li>Workflow run summary (for push trigger)</li></ul><h3 id="symbols" tabindex="-1">Symbols <a class="header-anchor" href="#symbols" aria-label="Permalink to &quot;Symbols&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Symbol</th><th>Meaning</th></tr></thead><tbody><tr><td>✅</td><td>Check passed</td></tr><tr><td>❌</td><td>Check failed — action required</td></tr><tr><td>⚠️</td><td>Warning — optional but recommended</td></tr><tr><td>🔴</td><td>Critical security issue — immediate action required</td></tr></tbody></table><h3 id="secret-detection" tabindex="-1">Secret Detection <a class="header-anchor" href="#secret-detection" aria-label="Permalink to &quot;Secret Detection&quot;">​</a></h3><p>If secrets are detected:</p><ol><li>The file path is reported (but NOT the secret content)</li><li><strong>IMMEDIATELY</strong> rotate the exposed credential</li><li>Add the file to <code>.gitignore</code> if it contains sensitive config</li><li>Remove the hardcoded value and use environment variables</li></ol><hr><h2 id="adding-custom-checks" tabindex="-1">Adding Custom Checks <a class="header-anchor" href="#adding-custom-checks" aria-label="Permalink to &quot;Adding Custom Checks&quot;">​</a></h2><p>To add custom compliance checks, edit <code>.github/workflows/repo-health-check.yml</code>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Add a new check in the &quot;Check repo compliance&quot; step:</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">if [ -f &quot;YOUR-FILE&quot; ]; then</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  echo &quot;- ✅ YOUR-FILE exists&quot; &gt;&gt; $GITHUB_STEP_SUMMARY</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">else</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  echo &quot;- ❌ YOUR-FILE missing&quot; &gt;&gt; $GITHUB_STEP_SUMMARY</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">fi</span></span></code></pre></div><p>For organization-wide scanning, add a new table section in the &quot;Scan all repos&quot; step following the existing pattern.</p><hr><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="required-secrets" tabindex="-1">Required Secrets <a class="header-anchor" href="#required-secrets" aria-label="Permalink to &quot;Required Secrets&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Secret</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><code>GITHUB_TOKEN</code></td><td>Provided automatically by GitHub Actions</td><td>Yes</td></tr></tbody></table><h3 id="optional-inputs" tabindex="-1">Optional Inputs <a class="header-anchor" href="#optional-inputs" aria-label="Permalink to &quot;Optional Inputs&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Input</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>scan_all_repos</code></td><td>boolean</td><td><code>false</code></td><td>Scan all repos in org</td></tr><tr><td><code>org</code></td><td>string</td><td><code>OpenSIN-AI</code></td><td>Organization to scan</td></tr></tbody></table><hr><h2 id="compliance-tiers" tabindex="-1">Compliance Tiers <a class="header-anchor" href="#compliance-tiers" aria-label="Permalink to &quot;Compliance Tiers&quot;">​</a></h2><p>Repositories are classified into tiers based on their role:</p><h3 id="tier-1-a2a-agents" tabindex="-1">Tier 1: A2A Agents <a class="header-anchor" href="#tier-1-a2a-agents" aria-label="Permalink to &quot;Tier 1: A2A Agents&quot;">​</a></h3><p>Must have: <code>AGENTS.md</code>, <code>agent.json</code>, topic <code>opnsin-agent</code>, <code>README.md</code> Examples: <code>A2A-SIN-TelegramBot</code>, <code>A2A-SIN-Google-Apps</code></p><h3 id="tier-2-mcp-servers" tabindex="-1">Tier 2: MCP Servers <a class="header-anchor" href="#tier-2-mcp-servers" aria-label="Permalink to &quot;Tier 2: MCP Servers&quot;">​</a></h3><p>Must have: <code>README.md</code>, <code>AGENTS.md</code>, <code>mcp-config.json</code>, topic <code>opnsin-mcp</code> Examples: <code>MCP-SIN-usebrowser</code>, <code>MCP-SIN-memory</code></p><h3 id="tier-3-infrastructure" tabindex="-1">Tier 3: Infrastructure <a class="header-anchor" href="#tier-3-infrastructure" aria-label="Permalink to &quot;Tier 3: Infrastructure&quot;">​</a></h3><p>Must have: <code>README.md</code>, <code>LICENSE</code>, <code>.gitignore</code> Examples: <code>OpenSIN-documentation</code>, <code>Template-SIN-Agent-Worker</code></p><h3 id="tier-4-utilities" tabindex="-1">Tier 4: Utilities <a class="header-anchor" href="#tier-4-utilities" aria-label="Permalink to &quot;Tier 4: Utilities&quot;">​</a></h3><p>Must have: <code>README.md</code>, <code>.gitignore</code> Examples: <code>scripts/</code>, <code>tools/</code></p><hr><h2 id="related-issues" tabindex="-1">Related Issues <a class="header-anchor" href="#related-issues" aria-label="Permalink to &quot;Related Issues&quot;">​</a></h2><ul><li><a href="https://github.com/OpenSIN-AI/OpenSIN-documentation/issues/95" target="_blank" rel="noreferrer">#95</a> — 20 repos missing AGENTS.md</li><li><a href="https://github.com/OpenSIN-AI/OpenSIN-documentation/issues/96" target="_blank" rel="noreferrer">#96</a> — 7 MCP servers without README</li><li><a href="https://github.com/OpenSIN-AI/OpenSIN-documentation/issues/97" target="_blank" rel="noreferrer">#97</a> — 8 repos missing GitHub topics</li></ul>`,63)])])}const g=t(o,[["render",s]]);export{u as __pageData,g as default};
